#include <stdio.h>
#include <string.h>
#include <stdlib.h>

#define BUFFER_SIZE 256

char input_buffer[BUFFER_SIZE];
int sensor_interval = 60;
int sensor_threshold = 100;
char device_name[64] = "sensor01";
int wifi_enabled = 1;

void apply_config(char* command) {
    char param[64];
    char value[128];
    
    sscanf(command, "%s %s", param, value);
    
    if(strcmp(param, "interval") == 0) {
        sensor_interval = atoi(value);
        printf("Set interval to %d\n", sensor_interval);
    }
    else if(strcmp(param, "threshold") == 0) {
        sensor_threshold = atoi(value);
        printf("Set threshold to %d\n", sensor_threshold);
    }
    else if(strcmp(param, "name") == 0) {
        strcpy(device_name, value);
        printf("Set device name to %s\n", device_name);
    }
    else if(strcmp(param, "wifi") == 0) {
        wifi_enabled = atoi(value);
        printf("Set wifi to %d\n", wifi_enabled);
    }
    else {
        printf("Unknown parameter\n");
    }
}

void process_serial_input() {
    if(fgets(input_buffer, BUFFER_SIZE, stdin) != NULL) {
        apply_config(input_buffer);
    }
}

void print_status() {
    printf("\n=== Device Configuration ===\n");
    printf("Device Name: %s\n", device_name);
    printf("Sensor Interval: %d seconds\n", sensor_interval);
    printf("Sensor Threshold: %d\n", sensor_threshold);
    printf("WiFi: %s\n", wifi_enabled ? "Enabled" : "Disabled");
    printf("===========================\n\n");
}

int main() {
    printf("IoT Device Configuration System\n");
    printf("Commands: interval <val>, threshold <val>, name <str>, wifi <0|1>\n");
    printf("Type 'status' to view current config, 'quit' to exit\n\n");
    
    while(1) {
        printf("> ");
        fflush(stdout);
        
        if(fgets(input_buffer, BUFFER_SIZE, stdin) == NULL) {
            break;
        }
        
        input_buffer[strcspn(input_buffer, "\n")] = 0;
        
        if(strcmp(input_buffer, "quit") == 0) {
            break;
        }
        else if(strcmp(input_buffer, "status") == 0) {
            print_status();
        }
        else if(strlen(input_buffer) > 0) {
            apply_config(input_buffer);
        }
    }
    
    printf("Shutting down...\n");
    return 0;
}